INSERT INTO player_annotations (id, player_id, author_id, type, content, document_id, created_at, updated_at) VALUES
(1001, 1073, 1000, 'internal', 'Pol és el porter titular indiscutible del primer equip. Reflexos excel·lents i bona col·locació. Cal treballar la sortida a les pilotes aèries dins l''àrea.', NULL, '2026-04-15 10:30:00', '2026-04-15 10:30:00'),
(1002, 1063, 1000, 'public', 'Pol, has tingut una millora molt notable en el posicionament defensiu aquest mes. Segueix amb la mateixa actitud!', NULL, '2026-04-20 11:00:00', '2026-04-20 11:00:00'),
(1003, 1075, 1000, 'internal', 'Marc mostra bona velocitat però li costa mantenir la concentració durant els 90 minuts. Treballem la resistència mental.', NULL, '2026-05-02 09:15:00', '2026-05-02 09:15:00'),
(1004, 1067, 1000, 'internal', 'Arnau és clarament el jugador amb millor visió de joc del juvenil. Candidat a capità la temporada que ve.', NULL, '2026-05-10 16:00:00', '2026-05-10 16:00:00'),
(1005, 1053, 1003, 'internal', 'Àlex ha sofert una lesió lleu al genoll esquerre. Caldrà vigilar la seva càrrega d''entrenament les properes setmanes.', NULL, '2026-04-08 18:45:00', '2026-04-08 18:45:00'),
(1006, 1059, 1003, 'internal', 'Joel s''ha recuperat bé de l''esguinç de turmell. Reincorporat a l''entrenament sense restriccions.', NULL, '2026-05-18 19:30:00', '2026-05-18 19:30:00'),
(1007, 1051, 1003, 'public', 'Roger, has fet una primera part de temporada excel·lent. El teu compromís i esforç es nota dia a dia.', NULL, '2026-04-25 10:00:00', '2026-04-25 10:00:00'),
(1008, 1039, 1003, 'public', 'Pol, bona temporada fins ara. Segueix treballant el joc de peus, és el teu punt de millora principal.', NULL, '2026-04-12 17:00:00', '2026-04-12 17:00:00'),
(1009, 1045, 1003, 'internal', 'Gerard té molts recursos ofensius però li cal millorar el pressing defensiu. Exercicis específics la setmana que ve.', NULL, '2026-05-05 20:00:00', '2026-05-05 20:00:00'),
(1010, 1039, 1003, 'internal', 'Gran millora en la sortida de porteria amb el peu. Continuem treballant-ho amb en Pau (entrenador de porters).', NULL, '2026-05-20 18:30:00', '2026-05-20 18:30:00'),
(1011, 1029, 1005, 'internal', 'Sergi és el millor porter de la categoria. Reflexos excel·lents per la seva edat. Potencial per a categories superiors.', NULL, '2026-04-18 18:45:00', '2026-04-18 18:45:00'),
(1012, 1035, 1005, 'public', 'Joel, la teva millora en el control de pilota ha estat notable. Molt content amb el teu progrés.', NULL, '2026-05-08 19:00:00', '2026-05-08 19:00:00'),
(1013, 1033, 1005, 'internal', 'Iker és molt intens però necessita aprendre a gestionar l''energia. Tendeix a saturar-se als últims 20 minuts.', NULL, '2026-04-28 18:30:00', '2026-04-28 18:30:00'),
(1014, 1022, 1004, 'public', 'Carla, ets la jugadora amb millor lectura del joc de tot el Benjamí. Segueix liderant!', NULL, '2026-05-15 20:30:00', '2026-05-15 20:30:00'),
(1015, 1025, 1004, 'internal', 'Àlex té molta projecció ofensiva però li falta treballar el joc d''esquena. Exercicis específics d''atacant.', NULL, '2026-04-22 20:00:00', '2026-04-22 20:00:00'),
(1016, 1019, 1004, 'public', 'Jordi, has millorat molt la teva sortida de pilota amb el peu esquerre. Molt bé!', NULL, '2026-05-20 20:15:00', '2026-05-20 20:15:00'),
(1017, 1011, 1004, 'public', 'Biel, primera temporada a la categoria i ja destacas pel teu posicionament. Molt ben fet!', NULL, '2026-04-10 18:30:00', '2026-04-10 18:30:00'),
(1018, 1014, 1004, 'internal', 'Marc és el defensa més fiable del Prebenjamí. Molt bon comunicador a l''àrea.', NULL, '2026-05-05 18:45:00', '2026-05-05 18:45:00'),
(1019, 1065, 1000, 'public', 'Marc, la teva velocitat amb pilota és un arma diferencial. Treballem la finalització per completar el teu joc.', NULL, '2026-05-12 21:30:00', '2026-05-12 21:30:00'),
(1020, 1069, 1000, 'internal', 'Gerard és el davanter amb millor ratio de gol de tota la pedrera. Seguiment especial per la temporada que ve.', NULL, '2026-05-25 21:00:00', '2026-05-25 21:00:00'),
(1021, 1064, 1000, 'public', 'Carla, la teva regularitat defensiva és un exemple per a tot l''equip. Ets molt important en l''estructura.', NULL, '2026-04-30 21:15:00', '2026-04-30 21:15:00'),
(1022, 1077, 1002, 'internal', 'Àlex és el pivot amb més potencial físic que he entrenat. Treball de posicionament els divendres.', NULL, '2026-05-08 21:45:00', '2026-05-08 21:45:00'),
(1023, 1073, 1002, 'public', 'Pol, has donat un salt de qualitat enorme des del principi de temporada. La teva implicació és total.', NULL, '2026-05-22 21:30:00', '2026-05-22 21:30:00'),
(1024, 1041, 1003, 'internal', 'Marc és el lateral dret més actiu de l''infantil. Cal polir el seu cross per tenir un jugador complet.', NULL, '2026-04-14 20:15:00', '2026-04-14 20:15:00'),
(1025, 1047, 1003, 'public', 'Àlex, la teva millora en la fase defensiva ha estat molt notable. Segueix treballant el posicionament!', NULL, '2026-05-18 20:00:00', '2026-05-18 20:00:00'),
(1026, 1043, 1003, 'internal', 'Arnau és el millor pivot de la seva edat a la categoria. Lectura de joc molt avançada per la seva edat.', NULL, '2026-05-28 20:30:00', '2026-05-28 20:30:00'),
(1027, 1071, 1001, 'internal', 'Iker necessita millorar la seva resistència aeròbica. Programa de treball físic complementari preparat.', NULL, '2026-05-10 21:00:00', '2026-05-10 21:00:00'),
(1028, 1067, 1001, 'internal', 'Arnau ha mostrat una progressió física extraordinària. És dels millors atletes de la pedrera.', NULL, '2026-05-20 21:30:00', '2026-05-20 21:30:00'),
(1029, 1055, 1001, 'public', 'Dani, el teu físic és una qualitat diferencial. Segueix treballant la resistència i la velocitat de reacció.', NULL, '2026-04-28 21:00:00', '2026-04-28 21:00:00'),
(1030, 1057, 1003, 'internal', 'Jordi és el davanter centre del futur de l''acadèmia. Cal protegir el seu desenvolupament i no precipitar el seu ascens.', NULL, '2026-05-15 21:15:00', '2026-05-15 21:15:00'),
(1031, 1080, 1000, 'public', 'Alba, la teva versatilitat és la teva millor arma. Pots jugar a múltiples posicions i ho fas molt bé.', NULL, '2026-05-28 21:45:00', '2026-05-28 21:45:00'),
(1032, 1076, 1000, 'internal', 'Anna és la jugadora amb millor visió de joc del primer equip. Cal donar-li més protagonisme als entrenaments.', NULL, '2026-05-30 22:00:00', '2026-05-30 22:00:00'),
(1033, 1079, 1000, 'internal', 'Jordi té un problema de motivació des del febrer. Cal fer un seguiment proper i parlar-hi sobre els seus objectius.', NULL, '2026-04-05 22:00:00', '2026-04-05 22:00:00'),
(1034, 1079, 1000, 'public', 'Jordi, hem notat una millora en la teva actitud les últimes setmanes. Segueix amb aquesta energia!', NULL, '2026-05-28 21:50:00', '2026-05-28 21:50:00'),
(1035, 1074, 1000, 'internal', 'Carla és la jugadora defensiva amb millor posicionament de tot el primer equip. Rendiment constant i fiable.', NULL, '2026-05-10 21:00:00', '2026-05-10 21:00:00');
INSERT INTO player_metrics (id, player_id, coach_id, session_id, date, metrics, evaluation, notes, created_at) VALUES
(1001, 1073, 1000, NULL, '2026-05-15', '{"velocitat":9,"resistencia":8,"tecnica":9,"tactica":8,"actitud":10}', 'Pol mostra uns valors excel·lents en tots els aspectes. Porter amb un potencial extraordinari. La seva comunicació amb la defensa ha millorat molt.', 'Avaluació mensual maig 2026', '2026-05-15 10:00:00'),
(1002, 1063, 1000, NULL, '2026-05-15', '{"velocitat":8,"resistencia":8,"tecnica":7,"tactica":9,"actitud":9}', 'Pol té una lectura tàctica molt madura per la seva edat. Cal seguir polint la tècnica individual.', 'Avaluació mensual maig 2026', '2026-05-15 10:00:00'),
(1003, 1065, 1000, NULL, '2026-05-15', '{"velocitat":10,"resistencia":7,"tecnica":8,"tactica":7,"actitud":8}', 'Marc és el jugador més ràpid de la categoria. Necessita treballar la resistència i la presa de decisions.', 'Avaluació mensual maig 2026', '2026-05-15 10:00:00'),
(1004, 1067, 1001, NULL, '2026-05-16', '{"velocitat":8,"resistencia":10,"tecnica":7,"tactica":9,"actitud":9}', 'Arnau té una capacitat física excepcional. El seu treball al gimnàs es nota clarament en el rendiment al camp.', 'Avaluació física mensual', '2026-05-16 10:00:00'),
(1005, 1069, 1000, NULL, '2026-05-15', '{"velocitat":8,"resistencia":7,"tecnica":9,"tactica":8,"actitud":9}', 'Gerard és el davanter més productiu del juvenil. Ratio de finalització excel·lent.', 'Avaluació mensual maig 2026', '2026-05-15 10:00:00'),
(1006, 1075, 1000, NULL, '2026-05-16', '{"velocitat":9,"resistencia":7,"tecnica":8,"tactica":7,"actitud":7}', 'Marc té qualitats físiques superiors però cal millorar la seva actitud en els entrenaments.', 'Avaluació mensual maig 2026', '2026-05-16 10:00:00'),
(1007, 1077, 1002, NULL, '2026-05-16', '{"velocitat":7,"resistencia":9,"tecnica":8,"tactica":8,"actitud":10}', 'Àlex és el porter amb millor actitud de tota la pedrera. El seu compromís és un exemple per als seus companys.', 'Avaluació mensual pivot/porter', '2026-05-16 10:00:00'),
(1008, 1051, 1003, NULL, '2026-05-14', '{"velocitat":7,"resistencia":8,"tecnica":8,"tactica":9,"actitud":9}', 'Roger és el porter cadet amb millor posicionament. La seva comunicació amb la defensa és excel·lent.', 'Avaluació Cadet A - maig', '2026-05-14 10:00:00'),
(1009, 1057, 1003, NULL, '2026-05-14', '{"velocitat":9,"resistencia":8,"tecnica":8,"tactica":8,"actitud":8}', 'Jordi mostra un gran potencial ofensiu. Cal treballar la seva participació en la construcció del joc.', 'Avaluació Cadet A - maig', '2026-05-14 10:00:00'),
(1010, 1055, 1001, NULL, '2026-05-14', '{"velocitat":8,"resistencia":9,"tecnica":7,"tactica":7,"actitud":8}', 'Dani té un físic excel·lent per la seva edat. Necessita millorar la tècnica individual.', 'Avaluació física Cadet A', '2026-05-14 10:00:00'),
(1011, 1039, 1003, NULL, '2026-05-13', '{"velocitat":7,"resistencia":7,"tecnica":8,"tactica":8,"actitud":9}', 'Pol és el porter infantil amb millor progrés de la temporada. La sortida de pilota ha millorat molt.', 'Avaluació Infantil A - maig', '2026-05-13 10:00:00'),
(1012, 1045, 1003, NULL, '2026-05-13', '{"velocitat":9,"resistencia":7,"tecnica":8,"tactica":7,"actitud":8}', 'Gerard té molta qualitat ofensiva però ha de millorar el seu treball defensiu.', 'Avaluació Infantil A - maig', '2026-05-13 10:00:00'),
(1013, 1043, 1003, NULL, '2026-05-13', '{"velocitat":7,"resistencia":8,"tecnica":8,"tactica":9,"actitud":10}', 'Arnau és el jugador més intel·ligent tàcticament de tot l''infantil. Actitud de líder.', 'Avaluació Infantil A - maig', '2026-05-13 10:00:00'),
(1014, 1029, 1005, NULL, '2026-05-12', '{"velocitat":8,"resistencia":7,"tecnica":8,"tactica":7,"actitud":9}', 'Sergi té reflexos excel·lents per la seva edat. Cal treballar la sortida a pilotes aèries.', 'Avaluació Aleví A - maig', '2026-05-12 10:00:00'),
(1015, 1035, 1005, NULL, '2026-05-12', '{"velocitat":9,"resistencia":8,"tecnica":7,"tactica":7,"actitud":8}', 'Joel és el davanter amb més gol de l''aleví. Necessita millorar la participació en el joc de construcció.', 'Avaluació Aleví A - maig', '2026-05-12 10:00:00'),
(1016, 1033, 1004, NULL, '2026-05-12', '{"velocitat":8,"resistencia":7,"tecnica":7,"tactica":8,"actitud":7}', 'Iker té molt potencial però necessita aprendre a gestionar la intensitat durant tota la sessió.', 'Avaluació Aleví A - maig', '2026-05-12 10:00:00'),
(1017, 1073, 1000, NULL, '2026-04-15', '{"velocitat":8,"resistencia":8,"tecnica":8,"tactica":7,"actitud":9}', 'Avaluació trimestral. Pol ha crescut molt com a porter. La millora més notable és en la comunicació i lideratge.', 'Avaluació trimestral abril 2026', '2026-04-15 10:00:00'),
(1018, 1067, 1001, NULL, '2026-04-15', '{"velocitat":8,"resistencia":9,"tecnica":7,"tactica":8,"actitud":9}', 'Arnau continua amb la seva progressió física. Un dels millors perfils físics de la categoria en anys.', 'Avaluació trimestral abril 2026', '2026-04-15 10:00:00'),
(1019, 1063, 1000, NULL, '2026-04-15', '{"velocitat":7,"resistencia":7,"tecnica":7,"tactica":8,"actitud":9}', 'Pol mostra una progressió constant. Jugador de procés, molt fiable i consistent.', 'Avaluació trimestral abril 2026', '2026-04-15 10:00:00'),
(1020, 1069, 1000, NULL, '2026-04-15', '{"velocitat":8,"resistencia":7,"tecnica":8,"tactica":7,"actitud":8}', 'Gerard ha tingut un bon primer trimestre. La seva capacitat de finalització és l''element diferencial.', 'Avaluació trimestral abril 2026', '2026-04-15 10:00:00');
