INSERT INTO messages (id, conversation_id, sender_id, body, file_path, file_name, file_size, file_mime, read_at, created_at) VALUES
(1001, 1001, 1000, 'Pol, bon entrenament avui. Com et trobes de les cames?', NULL, NULL, NULL, NULL, '2026-05-28 21:10:00', '2026-05-28 21:00:00'),
(1002, 1001, 1073, 'Gràcies míster. Una mica carregat però bé. Descansaré bé aquesta nit.', NULL, NULL, NULL, NULL, '2026-05-28 21:20:00', '2026-05-28 21:15:00'),
(1003, 1001, 1000, 'Perfecte. Recorda de fer els estiraments que et va indicar la Marta.', NULL, NULL, NULL, NULL, '2026-05-28 21:25:00', '2026-05-28 21:20:00'),
(1004, 1001, 1073, 'Sí, ja ho faré. Míster, vol dir que podré jugar el dissabte?', NULL, NULL, NULL, NULL, '2026-05-29 09:30:00', '2026-05-29 09:00:00'),
(1005, 1001, 1000, 'Si et trobes bé a l''entrenament de dijous, sí. Ja ho valorem.', NULL, NULL, NULL, NULL, '2026-05-29 09:45:00', '2026-05-29 09:30:00'),
(1006, 1001, 1073, 'Perfecte. Gràcies per tot, míster. A dijous!', NULL, NULL, NULL, NULL, NULL, '2026-06-01 21:45:00'),
(1007, 1002, 1000, 'Pol, volem parlar sobre la teva posició al camp. Pots venir uns minuts abans del proper entrenament?', NULL, NULL, NULL, NULL, '2026-05-25 15:00:00', '2026-05-25 09:00:00'),
(1008, 1002, 1063, 'Clar que sí, míster. Dimarts estaré aquí 15 minuts abans.', NULL, NULL, NULL, NULL, '2026-05-25 16:00:00', '2026-05-25 15:30:00'),
(1009, 1002, 1000, 'Perfecte. Parlarem del teu posicionament en les transicions defensives. Fins dimarts!', NULL, NULL, NULL, NULL, '2026-05-25 16:30:00', '2026-05-25 16:00:00'),
(1010, 1002, 1063, 'Entès, míster. Hi seré. Alguna cosa que hauria de repassar de vídeo?', NULL, NULL, NULL, NULL, '2026-05-27 20:00:00', '2026-05-27 19:00:00'),
(1011, 1002, 1000, 'Mira els últims 10 minuts del partit de dijous. Fixa''t en la teva posició quan perdem la pilota.', NULL, NULL, NULL, NULL, '2026-05-28 09:00:00', '2026-05-27 20:30:00'),
(1012, 1002, 1063, 'Ho he vist. Entenc el que voleu dir. Treballaré-ho.', NULL, NULL, NULL, NULL, NULL, '2026-05-28 20:30:00'),
(1013, 1003, 1039, 'Hola Pol, com va el genoll? Com et trobes per a l''entrenament de demà?', NULL, NULL, NULL, NULL, '2026-05-28 18:30:00', '2026-05-28 18:00:00'),
(1014, 1003, 1039, 'Hola entrenador! Avui millor que ahir. Crec que podré entrenar, però amb cura.', NULL, NULL, NULL, NULL, '2026-05-28 19:00:00', '2026-05-28 18:35:00'),
(1015, 1003, 1003, 'Perfecte. No forcis si notes alguna molèstia. Ja parlarem amb la Marta.', NULL, NULL, NULL, NULL, '2026-05-28 19:15:00', '2026-05-28 19:00:00'),
(1016, 1003, 1039, 'D''acord. Gràcies entrenador. A demà!', NULL, NULL, NULL, NULL, '2026-05-28 19:30:00', '2026-05-28 19:20:00'),
(1017, 1003, 1003, 'A demà! Fes els exercicis de mobilitat que et va dir la fisio.', NULL, NULL, NULL, NULL, '2026-05-29 18:00:00', '2026-05-29 09:00:00'),
(1018, 1003, 1039, 'Sí, els he fet tots avui al matí. Em trobo molt millor!', NULL, NULL, NULL, NULL, NULL, '2026-05-30 19:00:00'),
(1019, 1004, 1003, 'Roger, has fet un gran mes de maig. Volem donar-te més responsabilitat al camp la temporada que ve.', NULL, NULL, NULL, NULL, '2026-05-23 22:00:00', '2026-05-23 21:00:00'),
(1020, 1004, 1051, 'Moltes gràcies entrenador! Estic molt content. Treballaré molt dur.', NULL, NULL, NULL, NULL, '2026-05-24 08:00:00', '2026-05-23 22:15:00'),
(1021, 1004, 1003, 'Ho sé. Et veig molt madur per a la teva edat. Pensem en posar-te de capità la temporada que ve.', NULL, NULL, NULL, NULL, '2026-05-24 09:00:00', '2026-05-24 08:30:00'),
(1022, 1004, 1051, 'Seria un honor! Faré tot el possible per merèixer-ho.', NULL, NULL, NULL, NULL, '2026-05-24 10:00:00', '2026-05-24 09:30:00'),
(1023, 1004, 1003, 'Ho tinc clar. Segueix treballant com fins ara. Fins dijous!', NULL, NULL, NULL, NULL, '2026-05-24 10:30:00', '2026-05-24 10:00:00'),
(1024, 1004, 1051, 'A dijous entrenador! Moltes gràcies per tot.', NULL, NULL, NULL, NULL, NULL, '2026-05-25 21:15:00'),
(1025, 1005, 1004, 'Hola Jordi! Avui has fet un entrenament excel·lent. La teva sortida de pilota ha millorat moltíssim.', NULL, NULL, NULL, NULL, '2026-05-20 21:00:00', '2026-05-20 20:30:00'),
(1026, 1005, 1019, 'Gràcies entrenador! He estat practicant molt a casa.', NULL, NULL, NULL, NULL, '2026-05-20 21:15:00', '2026-05-20 21:00:00'),
(1027, 1005, 1004, 'Es nota! Continua practicant els tocs curts. La propera sessió farem circuits específics.', NULL, NULL, NULL, NULL, '2026-05-20 21:30:00', '2026-05-20 21:15:00'),
(1028, 1005, 1019, 'D''acord! Fins dilluns entrenador.', NULL, NULL, NULL, NULL, '2026-05-21 10:00:00', '2026-05-21 09:00:00'),
(1029, 1005, 1004, 'Fins dilluns! I recorda d''arribar 5 minuts abans per a l''escalfament.', NULL, NULL, NULL, NULL, '2026-05-21 11:00:00', '2026-05-21 10:00:00'),
(1030, 1005, 1019, 'Ho recordaré! Que passi un bon cap de setmana.', NULL, NULL, NULL, NULL, NULL, '2026-05-22 20:30:00'),
(1031, 1006, 1005, 'Sergi, avui has estat brillant entre els pals. Estàs millorant molt.', NULL, NULL, NULL, NULL, '2026-06-01 18:45:00', '2026-06-01 18:30:00'),
(1032, 1006, 1029, 'Gràcies Laia! Estic molt motivat amb l''entrenament de porters.', NULL, NULL, NULL, NULL, '2026-06-01 19:00:00', '2026-06-01 18:50:00'),
(1033, 1006, 1005, 'Es nota molt! Dimarts treballarem les eixides en les pilotes aèries específicament.', NULL, NULL, NULL, NULL, '2026-06-01 19:15:00', '2026-06-01 19:00:00'),
(1034, 1006, 1029, 'Perfecte! És el que més necessito millorar.', NULL, NULL, NULL, NULL, '2026-06-01 19:25:00', '2026-06-01 19:20:00'),
(1035, 1006, 1005, 'Exacte, ho has identificat molt bé. Fins dimarts!', NULL, NULL, NULL, NULL, '2026-06-01 19:30:00', '2026-06-01 19:25:00'),
(1036, 1006, 1029, 'Fins dimarts! Bona tarda.', NULL, NULL, NULL, NULL, NULL, '2026-06-01 18:45:00'),
(1037, 1007, 1000, 'Jordi, hem de parlar del programa de pre-temporada per als categories superiors. Pots enviar-me el teu pla?', NULL, NULL, NULL, NULL, '2026-05-28 09:30:00', '2026-05-28 09:00:00'),
(1038, 1007, 1001, 'Clar Marc. Te l''envio avui a la tarda. Havia pensat en 3 setmanes de condicionament base.', NULL, NULL, NULL, NULL, '2026-05-28 10:00:00', '2026-05-28 09:35:00'),
(1039, 1007, 1000, 'Perfecte. Inclou exercicis específics de velocitat per als davanters. L''any passat ens va fallar la fase final.', NULL, NULL, NULL, NULL, '2026-05-28 10:30:00', '2026-05-28 10:00:00'),
(1040, 1007, 1001, 'Entès. Dissenyaré circuits de velocitat explosiva i resistència específica per posicions.', NULL, NULL, NULL, NULL, '2026-05-28 11:00:00', '2026-05-28 10:30:00'),
(1041, 1007, 1000, 'Molt bé. Quedarem divendres per revisar-ho junts?', NULL, NULL, NULL, NULL, '2026-05-29 09:30:00', '2026-05-29 09:00:00'),
(1042, 1007, 1001, 'Perfecte, divendres a les 9:00 al despatx. Ho tindré llest.', NULL, NULL, NULL, NULL, NULL, '2026-05-30 10:00:00'),
(1043, 1008, 1000, 'Pau, com veus als porters de la pedrera? Algun amb projecció per al primer equip?', NULL, NULL, NULL, NULL, '2026-05-27 09:30:00', '2026-05-27 09:00:00'),
(1044, 1008, 1002, 'En Pol Masferrer és clarament el millor. Reflexos, anticipació i joc de peus excel·lents per la seva edat.', NULL, NULL, NULL, NULL, '2026-05-27 10:00:00', '2026-05-27 09:45:00'),
(1045, 1008, 1000, 'Ho pensava jo també. I el Sergi Mas de l''aleví?', NULL, NULL, NULL, NULL, '2026-05-27 10:30:00', '2026-05-27 10:00:00'),
(1046, 1008, 1002, 'Té molt potencial però li falta temps. Potser d''aquí 3-4 anys. Estic fent treball específic amb ell.', NULL, NULL, NULL, NULL, '2026-05-27 11:00:00', '2026-05-27 10:30:00'),
(1047, 1008, 1000, 'Molt bé. Segueix amb ell. Si pot pujar de categoria l''any vinent seria ideal.', NULL, NULL, NULL, NULL, '2026-05-28 09:30:00', '2026-05-28 09:00:00'),
(1048, 1008, 1002, 'D''acord. Li mantindré un programa personalitzat de porters.', NULL, NULL, NULL, NULL, NULL, '2026-05-29 09:30:00'),
(1049, 1009, 1003, 'Laia, has vist la millora de l''aleví en el pressing? Crec que les teves sessions tècniques estan donant fruits.', NULL, NULL, NULL, NULL, '2026-05-25 16:30:00', '2026-05-25 16:00:00'),
(1050, 1009, 1005, 'Sí! Estic molt contenta. L''Iker i la Mireia han millorat especialment.', NULL, NULL, NULL, NULL, '2026-05-25 17:00:00', '2026-05-25 16:35:00');
INSERT INTO messages (id, conversation_id, sender_id, body, file_path, file_name, file_size, file_mime, read_at, created_at) VALUES
(1051, 1009, 1003, 'Exacte. Podríem fer un treball conjunt entre l''aleví i l''infantil? Una sessió mixta de tècnica?', NULL, NULL, NULL, NULL, '2026-05-25 17:30:00', '2026-05-25 17:00:00'),
(1052, 1009, 1005, 'M''encanta la idea! Ho podem fer el divendres 13 de juny. Tenim els dos camps disponibles.', NULL, NULL, NULL, NULL, '2026-05-26 09:30:00', '2026-05-26 09:00:00'),
(1053, 1009, 1003, 'Perfecte, ho apunto. Avises en Roger per coordinar els espais?', NULL, NULL, NULL, NULL, '2026-05-26 10:00:00', '2026-05-26 09:30:00'),
(1054, 1009, 1005, 'Ja ho dic jo. Genial, serà una sessió molt productiva!', NULL, NULL, NULL, NULL, NULL, '2026-05-27 16:00:00'),
(1055, 1010, 1007, 'Marc, tinc cura especial amb en Joel Batlle (Cadet). El turmell millora però necessita 2 setmanes més sense joc real.', NULL, NULL, NULL, NULL, '2026-05-26 09:00:00', '2026-05-26 08:30:00'),
(1056, 1010, 1000, 'Entès Marta. El mantindré en sessions de gimnàs amb en Jordi. Res de camp fins que tu diguis.', NULL, NULL, NULL, NULL, '2026-05-26 09:30:00', '2026-05-26 09:00:00'),
(1057, 1010, 1007, 'Perfecte. L''Arnau Batlle del juvenil també el controlo per la pronació. Res alarmant però vigilem.', NULL, NULL, NULL, NULL, '2026-05-26 10:00:00', '2026-05-26 09:30:00'),
(1058, 1010, 1000, 'Gràcies per l''avís. Hauré de limitar els seus salts en els propers entrenaments?', NULL, NULL, NULL, NULL, '2026-05-27 09:30:00', '2026-05-27 09:00:00'),
(1059, 1010, 1007, 'Millor que sí. Evitar exercicis de salts repetitius. Passa''m el planning de la setmana i marco quins han d''adaptar.', NULL, NULL, NULL, NULL, '2026-05-27 10:00:00', '2026-05-27 09:30:00'),
(1060, 1010, 1000, 'Te''l passo avui. Gràcies Marta, com sempre!', NULL, NULL, NULL, NULL, NULL, '2026-05-28 10:30:00'),
(1061, 1011, 1007, 'Pol, com et trobes el turmell avui? L''entrenador m''ha dit que notaves molèstia ahir.', NULL, NULL, NULL, NULL, '2026-05-23 10:30:00', '2026-05-23 10:00:00'),
(1062, 1011, 1073, 'Hola Marta! Avui millor. Ahir estava una mica inflamat però he posat gel i he descansat.', NULL, NULL, NULL, NULL, '2026-05-23 11:00:00', '2026-05-23 10:45:00'),
(1063, 1011, 1007, 'Bé. Vine demà uns 20 minuts abans de l''entrenament i et faré una valoració ràpida.', NULL, NULL, NULL, NULL, '2026-05-23 11:30:00', '2026-05-23 11:00:00'),
(1064, 1011, 1073, 'D''acord Marta. Hi seré. Gràcies!', NULL, NULL, NULL, NULL, '2026-05-23 12:00:00', '2026-05-23 11:30:00'),
(1065, 1011, 1007, 'Perfecte. Porta equipament complet per si pots entrenar normal després.', NULL, NULL, NULL, NULL, '2026-05-24 09:30:00', '2026-05-24 09:00:00'),
(1066, 1011, 1073, 'Perfecte! Hi estaré.', NULL, NULL, NULL, NULL, NULL, '2026-05-25 11:00:00'),
(1067, 1012, 1007, 'Roger, com va la lesió? L''entrenador diu que entrenaves amb certa molèstia ahir.', NULL, NULL, NULL, NULL, '2026-05-18 10:00:00', '2026-05-18 09:30:00'),
(1068, 1012, 1051, 'Hola Marta! El turmell ja no em fa mal. Crec que estic totalment bé.', NULL, NULL, NULL, NULL, '2026-05-18 10:30:00', '2026-05-18 10:15:00'),
(1069, 1012, 1007, 'Bé, però anem amb compte. Vine divendres i et faig una revisió completa.', NULL, NULL, NULL, NULL, '2026-05-18 11:00:00', '2026-05-18 10:30:00'),
(1070, 1012, 1051, 'D''acord. Divendres a quina hora?', NULL, NULL, NULL, NULL, '2026-05-19 09:30:00', '2026-05-19 09:00:00'),
(1071, 1012, 1007, 'A les 17:30 al gimnàs, just abans de l''entrenament del Júnior.', NULL, NULL, NULL, NULL, '2026-05-19 10:00:00', '2026-05-19 09:30:00'),
(1072, 1012, 1051, 'Perfecte, hi estaré. Gràcies Marta!', NULL, NULL, NULL, NULL, NULL, '2026-05-20 10:00:00'),
(1073, 1013, 1008, 'Marc, he reservat dos autobusos per als últims dos partits de fora. Confirmes el nombre de jugadors?', NULL, NULL, NULL, NULL, '2026-05-24 08:30:00', '2026-05-24 08:00:00'),
(1074, 1013, 1000, 'Per al primer equip som 18 jugadors + 4 staff. Per al Júnior B 16 + 3 staff.', NULL, NULL, NULL, NULL, '2026-05-24 09:00:00', '2026-05-24 08:30:00'),
(1075, 1013, 1008, 'Perfecte. L''autobús gran té 54 places, podem anar tots junts si vols.', NULL, NULL, NULL, NULL, '2026-05-24 09:30:00', '2026-05-24 09:00:00'),
(1076, 1013, 1000, 'Millor anar junts, més econòmic. Reserva per a 45 persones.', NULL, NULL, NULL, NULL, '2026-05-25 08:30:00', '2026-05-25 08:00:00'),
(1077, 1013, 1008, 'Fet. Surtirem a les 9:30 del Camp Principal. Ho comunico als equips?', NULL, NULL, NULL, NULL, '2026-05-25 09:00:00', '2026-05-25 08:30:00'),
(1078, 1013, 1000, 'Sí, envia la informació per la plataforma a tots els convocats.', NULL, NULL, NULL, NULL, NULL, '2026-05-26 08:30:00'),
(1079, 1014, 1009, 'Arnau, falta material al Camp B: 3 porteries de minicamp s''han espatllat. Necessitem solució urgentament.', NULL, NULL, NULL, NULL, '2026-05-18 09:00:00', '2026-05-18 08:30:00'),
(1080, 1014, 1003, 'Gràcies per l''avís Toni. Comprova si les del magatzem es poden usar mentre.', NULL, NULL, NULL, NULL, '2026-05-18 09:30:00', '2026-05-18 09:00:00'),
(1081, 1014, 1009, 'Ho he mirat i dues estan en bon estat. Però no en tenim prou per a dos camps simultanis.', NULL, NULL, NULL, NULL, '2026-05-18 10:00:00', '2026-05-18 09:30:00'),
(1082, 1014, 1003, 'D''acord. Posa-ho a la llista de compres de la plataforma, prioritat alta.', NULL, NULL, NULL, NULL, '2026-05-19 09:00:00', '2026-05-19 08:30:00'),
(1083, 1014, 1009, 'Ja ho he fet. He posat el link a Amazon, cada porteria val uns 45€.', NULL, NULL, NULL, NULL, '2026-05-19 09:30:00', '2026-05-19 09:00:00'),
(1084, 1014, 1003, 'Perfecte. Ho valorem amb l''administració.', NULL, NULL, NULL, NULL, NULL, '2026-05-20 09:00:00'),
(1085, 1015, 1006, 'Marc, he elaborat un informe de rendiment de totes les categories. Te''l puc enviar?', NULL, NULL, NULL, NULL, '2026-05-26 09:30:00', '2026-05-26 09:00:00'),
(1086, 1015, 1000, 'Clar Roger, seria molt útil. Especialment per a la reunió amb la junta del 15 de juny.', NULL, NULL, NULL, NULL, '2026-05-26 10:00:00', '2026-05-26 09:30:00'),
(1087, 1015, 1006, 'Perfecte. Incluiré: assistència, resultats, progressió individual i proposta de canvis per a l''any vinent.', NULL, NULL, NULL, NULL, '2026-05-27 09:00:00', '2026-05-27 08:30:00'),
(1088, 1015, 1000, 'Afegeix també la proposta d''ascens de categoria per a alguns jugadors de la pedrera.', NULL, NULL, NULL, NULL, '2026-05-27 09:30:00', '2026-05-27 09:00:00'),
(1089, 1015, 1006, 'Ja ho tenia contemplat. Tinc 5 jugadors candidats a pujar. Ho detallaré.', NULL, NULL, NULL, NULL, '2026-05-28 09:00:00', '2026-05-28 08:30:00'),
(1090, 1015, 1000, 'Excel·lent feina Roger. Ens veiem el divendres abans de la junta.', NULL, NULL, NULL, NULL, NULL, '2026-05-28 12:00:00'),
(1091, 1016, 1004, 'Hola Biel! Quin bon primer entrenament has fet avui. Com t''has sentit?', NULL, NULL, NULL, NULL, '2026-03-11 19:00:00', '2026-03-11 18:30:00'),
(1092, 1016, 1011, 'Molt bé entrenador! M''ha agradat molt.', NULL, NULL, NULL, NULL, '2026-03-12 10:00:00', '2026-03-12 09:00:00'),
(1093, 1016, 1004, 'Molt bé! Practica a casa el toc de pilota amb el peu esquerre. El teu dret ja és molt bo.', NULL, NULL, NULL, NULL, '2026-03-12 11:00:00', '2026-03-12 10:00:00'),
(1094, 1016, 1011, 'D''acord! Ho practicaré cada dia.', NULL, NULL, NULL, NULL, '2026-03-13 10:00:00', '2026-03-13 09:00:00'),
(1095, 1016, 1004, 'Perfecte Biel! Fins dilluns que ve.', NULL, NULL, NULL, NULL, '2026-04-18 18:00:00', '2026-04-18 17:30:00'),
(1096, 1016, 1011, 'Fins dilluns entrenador!', NULL, NULL, NULL, NULL, NULL, '2026-04-20 18:00:00'),
(1097, 1017, 1003, 'Gerard, vull que siguis el responsable de l''escalfament la propera sessió. Prepara 10 minuts d''exercicis.', NULL, NULL, NULL, NULL, '2026-05-13 20:00:00', '2026-05-13 19:30:00'),
(1098, 1017, 1045, 'Entès entrenador! M''ho preparo bé. Puc usar els exercicis que hem fet al circuit?', NULL, NULL, NULL, NULL, '2026-05-13 21:00:00', '2026-05-13 20:30:00'),
(1099, 1017, 1003, 'Exacte, usa els circuits que coneixem. Afegeix-hi una activació específica de turmells i genolls.', NULL, NULL, NULL, NULL, '2026-05-14 09:00:00', '2026-05-14 08:30:00'),
(1100, 1017, 1045, 'D''acord! Ho tinc molt clar.', NULL, NULL, NULL, NULL, '2026-05-14 10:00:00', '2026-05-14 09:30:00');
INSERT INTO messages (id, conversation_id, sender_id, body, file_path, file_name, file_size, file_mime, read_at, created_at) VALUES
(1101, 1017, 1003, 'Molt bé Gerard. Estàs demostrant qualitats de lideratge importants.', NULL, NULL, NULL, NULL, '2026-05-14 10:30:00', '2026-05-14 10:00:00'),
(1102, 1017, 1045, 'Moltes gràcies entrenador. Intento aprendre molt de vosaltres.', NULL, NULL, NULL, NULL, NULL, '2026-05-15 19:30:00'),
(1103, 1018, 1001, 'Marc, com va el programa de força? Notes millora en la resistència als darrers minuts dels partits?', NULL, NULL, NULL, NULL, '2026-05-27 09:30:00', '2026-05-27 09:00:00'),
(1104, 1018, 1065, 'Sí Jordi! Noto que em canso menys als darrers 20 minuts. El programa funciona bé.', NULL, NULL, NULL, NULL, '2026-05-27 10:00:00', '2026-05-27 09:45:00'),
(1105, 1018, 1001, 'Excel·lent. La setmana que ve pujo lleugerament la intensitat. Podràs?', NULL, NULL, NULL, NULL, '2026-05-27 10:30:00', '2026-05-27 10:00:00'),
(1106, 1018, 1065, 'Sí, sense problema. Estic molt motivat amb el treball físic.', NULL, NULL, NULL, NULL, '2026-05-28 09:30:00', '2026-05-28 09:00:00'),
(1107, 1018, 1001, 'Molt bé. Si tot va bé el mes de juny et proposo un treball personalitzat de pre-temporada.', NULL, NULL, NULL, NULL, '2026-05-28 10:00:00', '2026-05-28 09:30:00'),
(1108, 1018, 1065, 'Seria genial! Moltes gràcies Jordi.', NULL, NULL, NULL, NULL, NULL, '2026-05-29 21:30:00'),
(1109, 1019, 1000, 'Marc, hem de parlar sobre la teva renovació per a la temporada que ve. Tens 5 minuts demà?', NULL, NULL, NULL, NULL, '2026-05-28 20:30:00', '2026-05-28 20:00:00'),
(1110, 1019, 1075, 'Clar míster! Estaré disponible quan vulgui.', NULL, NULL, NULL, NULL, '2026-05-28 21:00:00', '2026-05-28 20:35:00'),
(1111, 1019, 1000, 'Demà a les 19:30 al despatx, just abans de l''entrenament.', NULL, NULL, NULL, NULL, '2026-05-28 21:15:00', '2026-05-28 21:00:00'),
(1112, 1019, 1075, 'Perfecte, hi estaré. Puc saber si va bé la renovació?', NULL, NULL, NULL, NULL, '2026-05-29 09:30:00', '2026-05-29 09:00:00'),
(1113, 1019, 1000, 'Va molt bé :) Però millor parlem-ho en persona.', NULL, NULL, NULL, NULL, '2026-05-29 10:00:00', '2026-05-29 09:30:00'),
(1114, 1019, 1075, 'Perfecte! Moltes gràcies míster. Fins demà.', NULL, NULL, NULL, NULL, NULL, '2026-05-30 22:00:00'),
(1115, 1020, 1006, 'Núria, quants jugadors nous hem rebut a la plataforma aquest mes?', NULL, NULL, NULL, NULL, '2026-05-23 09:30:00', '2026-05-23 09:00:00'),
(1116, 1020, 1010, 'Hola Roger! Hem rebut 8 formularis d''inscripció nous. 5 confirmats, 3 pendents de documentació.', NULL, NULL, NULL, NULL, '2026-05-23 10:00:00', '2026-05-23 09:45:00'),
(1117, 1020, 1006, 'Molt bé. Pots enviar recordatori als 3 pendents? El termini és el 30 de juny.', NULL, NULL, NULL, NULL, '2026-05-23 10:30:00', '2026-05-23 10:00:00'),
(1118, 1020, 1010, 'Ja els he enviat un email avui al matí. Espero resposta en 48h.', NULL, NULL, NULL, NULL, '2026-05-24 09:30:00', '2026-05-24 09:00:00'),
(1119, 1020, 1006, 'Perfecte Núria. Com sempre, molt eficient!', NULL, NULL, NULL, NULL, '2026-05-24 10:00:00', '2026-05-24 09:30:00'),
(1120, 1020, 1010, 'Gràcies Roger! Si no responen en 48h els trucaem directament.', NULL, NULL, NULL, NULL, NULL, '2026-05-25 10:30:00');
INSERT INTO notifications (id, sender_id, type, title, body, file_path, file_name, file_size, created_at) VALUES
(1001, 2, 'group', 'Inici de temporada 2025/2026', 'Benvinguts a la nova temporada! Us informem dels horaris i calendari de totes les categories. Molt bona temporada a tothom!', NULL, NULL, NULL, '2026-03-02 09:00:00'),
(1002, 2, 'group', 'Canvi d''horari Benjamí A', 'A partir del 15 de març, els entrenaments del Benjamí A seran els dilluns i dimecres de 18:30 a 20:00 h al Camp B.', NULL, NULL, NULL, '2026-03-10 10:00:00'),
(1003, 1000, 'group', 'Convocatòria Torneig Prebenjamí', 'El dissabte 22 de març tenim el Torneig Local Prebenjamí al Camp Municipal. Presentació a les 9:00 h. Material requerit: equipament complet.', NULL, NULL, NULL, '2026-03-18 12:00:00'),
(1004, 2, 'group', 'Actualització de bonos temporada', 'Recordem que els bonos de la temporada es poden renovar a partir del mes d''abril. Consulteu les noves tarifes a la plataforma.', NULL, NULL, NULL, '2026-04-01 09:00:00'),
(1005, 1000, 'group', 'Torneig de Pasqua - Infantil A', 'Torneig de Pasqua el diumenge 13 d''abril. Presentació a les 10:00 h al Camp Principal. Portem equipament complet.', NULL, NULL, NULL, '2026-04-07 15:00:00'),
(1006, 1000, 'individual', 'Recordatori: Avaluació de rendiment', 'Recordem als jugadors de les categories Infantil, Cadet, Juvenil i Júnior que les avaluacions de rendiment es faran la setmana del 13 al 16 de maig.', NULL, NULL, NULL, '2026-05-08 10:00:00'),
(1007, 2, 'group', 'Festa de final de temporada', 'La Festa de Final de Temporada tindrà lloc el 28 de juny al Camp Principal. Més informació properament!', NULL, NULL, NULL, '2026-05-15 11:00:00'),
(1008, 1000, 'group', 'Canvi de camp - Cadet A', 'Per reformes al Camp B, els entrenaments del Cadet A es faran al Camp Principal fins a nova ordre.', NULL, NULL, NULL, '2026-05-20 09:00:00'),
(1009, 1003, 'individual', 'Protocol de recuperació per a jugador lesionat', 'S''ha establert un protocol de recuperació per a en Joel Batlle. La fisioterapeuta Marta farà seguiment personalitzat.', NULL, NULL, NULL, '2026-04-10 10:30:00'),
(1010, 2, 'group', 'Renovació d''inscripcions 2026/2027', 'Ja es pot formalitzar la inscripció per a la temporada 2026/2027. El termini per als actuals jugadors és el 30 de juny.', NULL, NULL, NULL, '2026-05-25 09:00:00'),
(1011, 1006, 'group', 'Nou portal de documentació', 'Ja teniu disponible la nova secció de documentació a la plataforma. Trobareu fitxes tècniques, reglaments i documents administratius.', NULL, NULL, NULL, '2026-04-20 11:00:00'),
(1012, 1000, 'individual', 'Incorporació temporal al Primer Equip', 'Informem de la incorporació temporal d''un jugador de la pedrera al primer equip per al proper cicle de competició.', NULL, NULL, NULL, '2026-05-10 12:00:00'),
(1013, 2, 'group', 'Mèdics i assegurances', 'Recordem que tots els jugadors han de tenir al dia la targeta federativa i l''assegurança esportiva. Consulteu el delegat si teniu dubtes.', NULL, NULL, NULL, '2026-03-20 10:00:00'),
(1014, 1001, 'group', 'Programa de preparació física d''estiu', 'Per als jugadors de categories superiors, hem preparat un programa de preparació física per a l''estiu. Consulteu el preparador físic.', NULL, NULL, NULL, '2026-05-28 09:00:00'),
(1015, 2, 'group', 'Benvinguda a la plataforma digital', 'Us donem la benvinguda a la plataforma digital de l''acadèmia. Aquí trobareu tota la informació: horaris, notes, bonos i comunicació directa amb els entrenadors.', NULL, NULL, NULL, '2026-03-02 08:00:00'),
(1016, 1000, 'individual', 'Selecció provincial - Felicitació', 'Comunicar que en Marc Mas (Juvenil A) ha estat convocat per a la selecció provincial sub-18. Enhorabona Marc!', NULL, NULL, NULL, '2026-05-05 13:00:00'),
(1017, 1006, 'group', 'Calendari - Darrers partits de temporada', 'Us adjuntem el calendari dels darrers partits de la temporada regular per a totes les categories. Cal confirmar assistència a la plataforma.', NULL, NULL, NULL, '2026-05-18 10:00:00'),
(1018, 2, 'group', 'Tancament temporal instal·lacions', 'Les instal·lacions estaran tancades del 28 d''agost al 4 de setembre per manteniment anual. Represa: 7 de setembre.', NULL, NULL, NULL, '2026-06-01 09:00:00');
